body:
In the following example reduced from UVM tests/70regs/01fields/03rand, despite a call to fA1.rand_mode(0), the fA1 object gets randomized.

I noted there's a t_constraint_global_nested_randmode, so this appears to intended to be supported.

@YilouWang might you get a chance to look into this?  Thanks.

<details>
<summary>Example</summary>

```
// verilog_format: off
`define stop $stop
`define checkd(gotv,expv) do if ((gotv) !== (expv)) begin $write("%%Error: %s:%0d:  got=%0d exp=%0d\n", `__FILE__,`__LINE__, (gotv), (expv)); `stop; end while(0);
`define checkh(gotv,expv) do if ((gotv) !== (expv)) begin $write("%%Error: %s:%0d:  got='h%x exp='h%x\n", `__FILE__,`__LINE__, (gotv), (expv)); `stop; end while(0);
// verilog_format: on

typedef logic [31:0] uvm_reg_data_t;

class uvm_object;
endclass

class uvm_reg_field extends uvm_object;
  rand uvm_reg_data_t value;
  int unsigned m_size;

  function uvm_reg_data_t get;
    return value;
  endfunction

  function void set_rand_mode(bit rand_mode);
    value.rand_mode(rand_mode);
    uvm_reg_field_valid.constraint_mode(rand_mode);
  endfunction

  function bit get_rand_mode();
    return bit'(value.rand_mode());
  endfunction

  // verilator lint_off WIDTH
  constraint uvm_reg_field_valid {
    if (64 > m_size) {
      value < (64'h1 << m_size);
    }
  }
  // verilator lint_on WIDTH

  function void configure(int unsigned size);
    m_size = size;
  endfunction
endclass

class uvm_reg extends uvm_object;
  virtual function void build();
  endfunction
endclass

class regA extends uvm_reg;
  rand uvm_reg_field fA1;
  rand uvm_reg_field fA2;

  virtual function void build();
    this.fA1 = new;
    this.fA2 = new;
    this.fA1.configure(16);
    this.fA2.configure(16);
  endfunction
endclass

class test extends uvm_object;
  regA rg;

  function new;
    rg = new;
    rg.build();
  endfunction

  task run_test;
    uvm_reg_data_t pre_randomized_value_fA1;
    uvm_reg_data_t pre_randomized_value_fA2;

    rg.fA1.set_rand_mode(0);
    rg.fA2.set_rand_mode(1);
    `checkd(rg.fA1.get_rand_mode(), 0);
    `checkd(rg.fA2.get_rand_mode(), 1);

    pre_randomized_value_fA1 = rg.fA1.value;
    pre_randomized_value_fA2 = rg.fA2.value;

    if (rg.randomize()) begin
      `checkh(rg.fA1.get(), pre_randomized_value_fA1);
    end
  endtask

endclass

module top;
  initial begin
    test t;
    t = new;
    t.run_test();
  end
endmodule
```
</details>

